// fetch con token de autorización
async function obtenerPerfil() {
  const token = localStorage.getItem('accessToken');

  const res = await fetch('/api/perfil', {
    headers: { 'Authorization': `Bearer ${token}` }
  });

  if (res.status === 401) throw new Error('Sesión expirada');
  if (!res.ok) throw new Error(`Error ${res.status}`);

  return res.json();
}

// Función genérica para toda la API
async function api(ruta, { method = 'GET', body, headers = {} } = {}) {
  const token = localStorage.getItem('token');
  const opciones = {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...(token && { 'Authorization': `Bearer ${token}` }),
      ...headers
    }
  };
  if (body) opciones.body = JSON.stringify(body);

  const res = await fetch(`/api${ruta}`, opciones);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
}

// Todas las peticiones usan la misma base
const usuarios = await api('/usuarios');
const nuevo = await api('/posts', { method: 'POST', body: { titulo: 'Hola' } });
await api(`/tareas/${id}`, { method: 'DELETE' });

// Reintentos automáticos en caso de error de red
async function fetchConReintento(url, opciones = {}, intentos = 3) {
  for (let i = 0; i < intentos; i++) {
    try {
      const res = await fetch(url, opciones);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return await res.json();
    } catch (error) {
      const esElUltimo = i === intentos - 1;
      if (esElUltimo) throw error; // agota reintentos
      await new Promise(r => setTimeout(r, 1000 * (i + 1))); // espera 1s, 2s...
      console.log(`Reintentando... (intento ${i + 2}/${intentos})`);
    }
  }
}

