function crearHeaders(token) {
  const headers = { 'Content-Type': 'application/json' };
  if (token) headers['Authorization'] = `Bearer ${token}`;
  return headers;
}

const conToken = crearHeaders('mi-token-123');
const sinToken = crearHeaders(null);

function manejarStatus(status) {
  if (status >= 200 && status < 300) return 'éxito';
  if (status === 401) return 'no autorizado';
  if (status === 404) return 'no encontrado';
  if (status >= 500) return 'error del servidor';
  return 'desconocido';
}

function mockFetch(url, opciones = {}) {
  const esPOST = opciones.method === 'POST';
  return Promise.resolve({
    ok: true,
    status: esPOST ? 201 : 200,
    json: () => Promise.resolve({ url, method: opciones.method || 'GET', body: opciones.body })
  });
}

function crearCliente(baseUrl, _fetch = mockFetch) {
  async function peticion(ruta, opciones = {}) {
    const res = await _fetch(`${baseUrl}${ruta}`, {
      ...opciones,
      headers: { 'Content-Type': 'application/json', ...opciones.headers }
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.json();
  }

  return {
    get: (ruta) => peticion(ruta),
    post: (ruta, datos) => peticion(ruta, { method: 'POST', body: JSON.stringify(datos) })
  };
}

const cliente = crearCliente('https://api.ejemplo.com');
const getDatos = await cliente.get('/usuarios');
const postDatos = await cliente.post('/usuarios', { nombre: 'Ana' });
